css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #faf8f5; color: #2a2522; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #aaa; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #2a2522; }
.hero { padding: 50px 60px 70px; max-width: 720px; }
.hero h1 { font-size: 54px; font-weight: 800; line-height: 1.2; margin-bottom: 20px; }
.hero h1 span { color: #d97706; }
.hero p { color: #8a8077; font-size: 16px; line-height: 1.8; max-width: 500px; }
.gallery { padding: 0 60px 70px; }
.gallery h2 { font-size: 28px; font-weight: 800; margin-bottom: 30px; }
.brand-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 24px; }
.brand-card { cursor: pointer; }
.brand-visual { aspect-ratio: 1; border-radius: 20px; display: flex; align-items: center; justify-content: center; font-size: 64px; margin-bottom: 14px; transition: 0.2s; color: white; }
.brand-card:hover .brand-visual { transform: scale(1.03); }
.v1 { background: linear-gradient(150deg, #d97706, #92400e); }
.v2 { background: linear-gradient(150deg, #1e293b, #0f172a); }
.v3 { background: linear-gradient(150deg, #65a30d, #3f6212); }
.v4 { background: linear-gradient(150deg, #be123c, #881337); }
.brand-card h3 { font-size: 17px; font-weight: 700; margin-bottom: 4px; }
.brand-card span { font-size: 13px; color: #aaa; }
.approach { padding: 70px 60px; background: white; }
.approach h2 { font-size: 28px; font-weight: 800; text-align: center; margin-bottom: 36px; }
.approach-row { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 30px; max-width: 900px; margin: 0 auto; }
.approach-item { text-align: center; }
.anum { display: inline-block; font-size: 13px; font-weight: 800; color: #d97706; background: #fef3c7; padding: 6px 14px; border-radius: 999px; margin-bottom: 14px; }
.approach-item h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; }
.approach-item p { color: #8a8077; font-size: 13.5px; line-height: 1.6; }
.contact { text-align: center; padding: 80px 60px; }
.contact h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: #8a8077; font-size: 14px; margin-bottom: 26px; }
.contact button { background: #2a2522; color: white; border: none; padding: 15px 32px; border-radius: 4px; font-size: 14px; font-weight: 700; cursor: pointer; }
.modal { position: fixed; inset: 0; background: rgba(42,37,34,0.5); display: none; align-items: center; justify-content: center; padding: 20px; z-index: 10; }
.modal.show { display: flex; }
.modal-content { background: white; border-radius: 16px; padding: 30px; max-width: 420px; width: 100%; }
.modal-visual { aspect-ratio: 1; border-radius: 16px; display: flex; align-items: center; justify-content: center; font-size: 70px; margin-bottom: 18px; color: white; }
.modal-content h2 { font-size: 22px; font-weight: 800; margin-bottom: 4px; }
.modal-content span { display: block; color: #aaa; font-size: 13px; font-weight: 600; margin-bottom: 14px; }
.modal-content p { color: #8a8077; font-size: 14px; line-height: 1.7; margin-bottom: 22px; }
.close-btn { background: #2a2522; color: white; border: none; padding: 12px 28px; border-radius: 4px; font-size: 14px; font-weight: 700; cursor: pointer; width: 100%; }
@media (max-width: 900px) { .navbar, .hero, .gallery, .approach, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 34px; } }

