const brands = {
  'Lumen Kahve': { visual: '◐', cls: 'v1', sub: 'Logo & Ambalaj Tasarımı', desc: 'Sıcak ve davetkar bir kahve markası için minimalist logo, ambalaj sistemi ve mağaza içi görsel kimlik tasarladık.' },
  'Nexa Teknoloji': { visual: '◆', cls: 'v2', sub: 'Kurumsal Kimlik', desc: 'B2B teknoloji şirketi için güven veren, modern ve sade bir kurumsal kimlik sistemi geliştirdik.' },
  'Olive & Co': { visual: '●', cls: 'v3', sub: 'Marka Kitabı & Web', desc: 'Organik gıda markası için doğal renk paleti, tipografi ve kapsamlı marka kılavuzu hazırladık.' },
  'Peak Spor': { visual: '▲', cls: 'v4', sub: 'Logo & Tipografi Sistemi', desc: 'Dinamik ve enerjik bir spor markası için güçlü bir logo ve özel tipografi sistemi tasarladık.' }
};

function openBrand(el) {
  const title = el.querySelector('h3').textContent;
  const data = brands[title];
  if (!data) return;
  const visual = document.getElementById('modalVisual');
  visual.textContent = data.visual;
  visual.className = `modal-visual ${data.cls}`;
  document.getElementById('modalTitle').textContent = title;
  document.getElementById('modalSub').textContent = data.sub;
  document.getElementById('modalDesc').textContent = data.desc;
  document.getElementById('modal').classList.add('show');
}

function closeModal(e) {
  if (e.target.id === 'modal' || e.target.classList.contains('close-btn')) {
    document.getElementById('modal').classList.remove('show');
  }
}

